  sender_id: string;
  receiver_id: string;
  content: string;
  created_at: string;
  type?: 'text' | 'image' | 'audio';
  media_url?: string;
  room_id?: string;
}

export interface Notification {
  id: string;
  user_id: string;
  sender_id: string;
  type: 'like' | 'comment' | 'follow';
  reference_id: string;
  is_read: boolean;
  created_at: string;
  sender_profile?: Profile; // Virtual/Joined
  media_url?: string; // Virtual/Joined for post thumbnail
